154→export const generateRubricTool = tool({
155→  description: `Generate a scoring rubric for an evaluation criterion.
156→Creates detailed descriptions for each score level.
157→Use to establish consistent evaluation standards.`,
158→  parameters: GenerateRubricInputSchema,
159→  execute: executeGenerateRubric
160→});
